import{_ as o,C as r,o as n,c as t,a2 as s,E as i}from"./chunks/framework.BKG_UbFK.js";const k=JSON.parse('{"title":"Permissões","description":"","frontmatter":{},"headers":[],"relativePath":"pt/features/permissions.md","filePath":"pt/features/permissions.md"}'),p={name:"pt/features/permissions.md"};function l(d,e,c,m,h,u){const a=r("Screenshot");return n(),t("div",null,[e[0]||(e[0]=s('<h1 id="permissoes" tabindex="-1">Permissões <a class="header-anchor" href="#permissoes" aria-label="Permalink to &quot;Permissões&quot;">​</a></h1><p>O painel de Permissões é uma interface CRUD completa sobre o modelo <code>Permission</code> do Spatie. O Clearance nunca introduz a sua própria tabela de permissões - toda a permissão que cria aqui é uma permissão Spatie normal, utilizável em qualquer lugar onde a API do Spatie seja usada (<code>$user-&gt;can()</code>, <code>Gate::allows()</code>, políticas, <code>@can</code>).</p><h2 id="o-que-o-painel-faz" tabindex="-1">O que o painel faz <a class="header-anchor" href="#o-que-o-painel-faz" aria-label="Permalink to &quot;O que o painel faz&quot;">​</a></h2><ul><li><strong>Criar</strong> - adicionar uma nova permissão, validada contra a <a href="#convenção-de-nomenclatura-de-permissões">convenção de nomenclatura</a> (a menos que desativada) e delimitada a um guard.</li><li><strong>Editar</strong> - renomear uma permissão ou alterar o seu guard.</li><li><strong>Eliminar</strong> - remover uma permissão e as suas atribuições de papel/utilizador (comportamento de cascade padrão do Spatie).</li></ul>',4)),i(a,{src:"/screenshots/permissions-page.png",alt:"Painel de Permissões do Clearance a listar permissões agrupadas por prefixo de nomenclatura",caption:"O painel de Permissões lista todas as permissões do Spatie, agrupadas por prefixo de nomenclatura."}),i(a,{src:"/screenshots/permission-form-modal.png",alt:"Formulário de criação/edição de permissão com validação da convenção de nomenclatura",caption:"O formulário de permissão valida a convenção de nomenclatura group-action antes de gravar."}),e[1]||(e[1]=s(`<h2 id="convencao-de-nomenclatura-de-permissoes" tabindex="-1">Convenção de Nomenclatura de Permissões <a class="header-anchor" href="#convencao-de-nomenclatura-de-permissoes" aria-label="Permalink to &quot;Convenção de Nomenclatura de Permissões&quot;">​</a></h2><p>As permissões devem seguir o formato <code>group-action</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>orders-create       correct</span></span>
<span class="line"><span>orders-read         correct</span></span>
<span class="line"><span>store-orders-delete correct</span></span>
<span class="line"><span></span></span>
<span class="line"><span>create              wrong (bare action, no group)</span></span>
<span class="line"><span>orders.create       wrong (dot separator)</span></span>
<span class="line"><span>Orders-Create       wrong (camelCase)</span></span></code></pre></div><p>O prefixo do grupo (<code>orders</code> em <code>orders-create</code>) é o que o <a href="/clearance-docs/pt/features/dashboard.html">Painel de Controle</a> usa para contar grupos de permissões distintos.</p><div class="tip custom-block"><p class="custom-block-title">Desativar a imposição</p><p>Algumas equipas migram de um esquema de nomenclatura diferente. Desative a verificação por ambiente:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// config/clearance.php</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;enforce_naming_convention&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span></code></pre></div></div><h2 id="controlo-de-acesso" tabindex="-1">Controlo de acesso <a class="header-anchor" href="#controlo-de-acesso" aria-label="Permalink to &quot;Controlo de acesso&quot;">​</a></h2><p>O acesso de leitura ao painel (ver a lista de permissões) requer <code>clearance-access</code>. Criar, editar, ou eliminar uma permissão requer adicionalmente <code>clearance-permissions-write</code>:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;clearance-access&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;clearance-permissions-write&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">As permissões <code>clearance-*</code> são reservadas</p><p>As próprias permissões <code>clearance-*</code> (<code>clearance-access</code>, <code>clearance-permissions-write</code>, etc.) não podem ser criadas, renomeadas, ou eliminadas através deste painel - mesmo por um ator <code>super_admin</code>. São geridas exclusivamente pelo próprio fluxo de instalação do pacote. Ver <a href="/clearance-docs/pt/features/super-admin.html#permissões-clearance-reservadas">Super Admin</a>.</p></div><h2 id="rota-e-componente-incorporado" tabindex="-1">Rota e componente incorporado <a class="header-anchor" href="#rota-e-componente-incorporado" aria-label="Permalink to &quot;Rota e componente incorporado&quot;">​</a></h2><table tabindex="0"><thead><tr><th>URI</th><th>Nome da rota</th><th>Descrição</th></tr></thead><tbody><tr><td><code>/clearance/permissions</code></td><td><code>clearance.permissions</code></td><td>CRUD de Permissões com validação de nomenclatura por prefixo de grupo</td></tr></tbody></table><div class="language-blade vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">blade</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">livewire:clearance::permissions.permission-manager</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span></code></pre></div><h2 id="proximos-passos" tabindex="-1">Próximos passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Próximos passos&quot;">​</a></h2><ul><li><a href="/clearance-docs/pt/features/roles.html">Papéis</a> - atribuir permissões a um papel, delimitado ao guard.</li><li><a href="/clearance-docs/pt/features/super-admin.html">Super Admin</a> - a tabela completa de permissões de escrita granulares.</li><li><a href="/clearance-docs/pt/guide/configuration.html">Referência de configuração</a> - <code>enforce_naming_convention</code>, <code>naming_separator</code>.</li></ul>`,14))])}const v=o(p,[["render",l]]);export{k as __pageData,v as default};
